export type CityEntry = {
  slug: string;
  country: string;
  countrySlug: string;
  city: string;
  region: string;
  subregion: string;
  isCapital: boolean;
  salary: string;
  salaryNote: string;
  demand: "Very High" | "High" | "Medium" | "Low";
  priority: boolean; // true = full detail page, false = template page
};

// Demand badge colours (used in UI)
export const DEMAND_STYLE: Record<string, { bg: string; color: string }> = {
  "Very High": { bg: "rgba(0,160,100,0.12)",  color: "#007850" },
  "High":      { bg: "rgba(0,120,200,0.12)",  color: "#005f90" },
  "Medium":    { bg: "rgba(140,90,0,0.10)",   color: "#7a5000" },
  "Low":       { bg: "rgba(100,100,100,0.10)", color: "#555555" },
};

export function getCityBySlug(slug: string): CityEntry | undefined {
  return CITIES.find((c) => c.slug === slug);
}

export function getCitiesByCountry(countrySlug: string): CityEntry[] {
  return CITIES.filter((c) => c.countrySlug === countrySlug);
}

export function getCitiesByRegion(region: string): CityEntry[] {
  return CITIES.filter((c) => c.region.toLowerCase() === region.toLowerCase());
}

export function getCitiesBySubregion(subregion: string): CityEntry[] {
  return CITIES.filter((c) => c.subregion === subregion);
}

export function getAllRegions(): string[] {
  return [...new Set(CITIES.map((c) => c.region))].sort();
}

export function getAllSubregions(): string[] {
  return [...new Set(CITIES.map((c) => c.subregion))].sort();
}

